import{_ as i,c as e,a3 as a,o as p}from"./chunks/framework.VX8o9GSp.js";const c=JSON.parse('{"title":"OpenSSL 加解密学习笔记","description":"","frontmatter":{"prev":false,"next":false,"date":"2024-10-06T00:00:00.000Z","tags":["OpenSSL","加密"],"categories":["计算机"]},"headers":[],"relativePath":"2024/10/OpenSSL 加解密学习笔记.md","filePath":"2024/10/OpenSSL 加解密学习笔记.md","lastUpdated":1728823343000}'),n={name:"2024/10/OpenSSL 加解密学习笔记.md"};function l(t,s,h,d,k,o){return p(),e("div",null,s[0]||(s[0]=[a(`<h1 id="openssl-加解密学习笔记" tabindex="-1">OpenSSL 加解密学习笔记 <a class="header-anchor" href="#openssl-加解密学习笔记" aria-label="Permalink to &quot;OpenSSL 加解密学习笔记&quot;">​</a></h1><h2 id="加解密命令" tabindex="-1">加解密命令 <a class="header-anchor" href="#加解密命令" aria-label="Permalink to &quot;加解密命令&quot;">​</a></h2><p>加密命令：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -aes-256-cbc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pbkdf2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -iter</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 20000</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pass</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pass:somepassword</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -in</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./sometext.txt</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -out</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./sometext.txt.enc</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这是一个使用 OpenSSL 的命令行命令，用于加密文件内容。下面是对这个命令的详细解释：</p><ul><li><p><code>openssl</code>: 这是 OpenSSL 的命令行工具，用于处理各种加密操作。</p></li><li><p><code>enc</code>: 这是 OpenSSL 的一个子命令，用于处理各种编码和解码操作。</p></li><li><p><code>-p</code>: 这个选项会打印出加密过程中使用的盐值（salt）和密钥。</p></li><li><p><code>-aes-256-cbc</code>: 这是加密算法的名称，这里使用的是 AES 256 位的 CBC 模式。</p></li><li><p><code>-pbkdf2</code>: 这是一个密码基础的密钥派生函数，用于从密码生成密钥。</p></li><li><p><code>-iter 20000</code>: 这个选项设置了 PBKDF2 函数的迭代次数。</p></li><li><p><code>-pass pass:somepassword</code>: 这个选项设置了用于生成密钥的密码。</p></li><li><p><code>-in ./sometext.txt</code>: 这个选项指定了要加密的输入文件。</p></li><li><p><code>-out ./sometext.txt.enc</code>: 这个选项指定了加密后的输出文件。</p></li></ul><p>总的来说，这个命令使用了 AES-256-CBC 算法和 PBKDF2 密钥派生函数，以及一个密码，对一个文件进行了加密，并将加密后的结果输出到另一个文件。同时，它还会打印出加密过程中使用的盐值和密钥。</p><p>加密命令：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -aes-256-cbc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pbkdf2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -iter</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 20000</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pass</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pass:somepassword</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -in</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./sometext.txt.enc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -out</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./sometext.txt</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这是一个使用 OpenSSL 的命令行命令，用于解密文件内容。下面是对这个命令的详细解释：</p><ul><li><p><code>openssl</code>: 这是 OpenSSL 的命令行工具，用于处理各种加密操作。</p></li><li><p><code>enc</code>: 这是 OpenSSL 的一个子命令，用于处理各种编码和解码操作。</p></li><li><p><code>-d</code>: 这个选项表示我们要进行解密操作。</p></li><li><p><code>-p</code>: 这个选项会打印出解密过程中使用的盐值（salt）和密钥。</p></li><li><p><code>-aes-256-cbc</code>: 这是加密算法的名称，这里使用的是 AES 256 位的 CBC 模式。</p></li><li><p><code>-pbkdf2</code>: 这是一个密码基础的密钥派生函数，用于从密码生成密钥。</p></li><li><p><code>-iter 20000</code>: 这个选项设置了 PBKDF2 函数的迭代次数。</p></li><li><p><code>-pass pass:somepassword</code>: 这个选项设置了用于生成密钥的密码。</p></li><li><p><code>-in ./sometext.txt.enc</code>: 这个选项指定了要解密的输入文件。</p></li><li><p><code>-out ./sometext.txt</code>: 这个选项指定了解密后的输出文件。</p></li></ul><p>总的来说，这个命令使用了 AES-256-CBC 算法和 PBKDF2 密钥派生函数，以及一个密码，对一个加密的文件进行解密，并将解密后的结果输出到另一个文件。同时，它还会打印出解密过程中使用的盐值和密钥。</p><hr><h2 id="用文件密钥加密" tabindex="-1">用文件密钥加密 <a class="header-anchor" href="#用文件密钥加密" aria-label="Permalink to &quot;用文件密钥加密&quot;">​</a></h2><p>OpenSSL 的 <code>enc</code> 命令不直接支持同时使用密码和密钥文件进行加密</p><p>OpenSSL支持许多加密算法，其中一些可以使用文件密钥和数字密钥一起进行加密。在这种情况下，通常会使用一个密钥派生函数（如PBKDF2或scrypt）来从文件密钥和数字密钥派生出一个加密密钥。</p><p>例如，你可以使用以下命令来使用AES-256-CBC模式和PBKDF2密钥派生函数进行加密：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -aes-256-cbc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pbkdf2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -in</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plaintext.txt</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -out</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ciphertext.bin</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pass</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> file:./keyfile</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>解密：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -aes-256-cbc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pbkdf2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -in</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ciphertext.bin</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -out</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plaintext.txt</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pass</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> file:./keyfile</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>在这个命令中：</p><ul><li><code>enc -aes-256-cbc</code>表示使用AES-256-CBC模式进行加密。</li><li><code>-pbkdf2</code>表示使用PBKDF2密钥派生函数。</li><li><code>-in plaintext.txt</code>表示输入文件是<code>plaintext.txt</code>。</li><li><code>-out ciphertext.bin</code>表示输出文件是<code>ciphertext.bin</code>。</li><li><code>-pass file:./keyfile</code>表示密码是从文件<code>./keyfile</code>中读取的。</li></ul><p>注意，这只是一个示例。实际使用时，你应该根据你的具体需求和环境选择合适的加密算法和密钥派生函数，并妥善保管你的密钥。</p><h2 id="生成一个包含随机数据的二进制文件" tabindex="-1">生成一个包含随机数据的二进制文件 <a class="header-anchor" href="#生成一个包含随机数据的二进制文件" aria-label="Permalink to &quot;生成一个包含随机数据的二进制文件&quot;">​</a></h2><p>你可以使用OpenSSL的<code>rand</code>命令来生成一个无意义的二进制文件。以下是一个示例：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rand</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -out</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> random.bin</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1024</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>在这个命令中：</p><ul><li><code>rand</code>是OpenSSL的一个命令，用于生成随机数。</li><li><code>-out random.bin</code>表示输出文件是<code>random.bin</code>。</li><li><code>1024</code>是一个参数，表示要生成的随机数的字节数。</li></ul><p>这个命令会生成一个包含1024字节随机数据的文件 <code>random.bin</code>。</p><p>你可以根据需要更改这个命令。例如，如果你想生成一个更大的文件，你可以将 <code>1024</code> 更改为其他的数字。</p><p><code>1024</code>在这个命令中表示的是生成1024字节（即1KB）的随机数据。在计算机中，1KB等于1024字节。</p><p>如果你想生成一个1024KB（即1MB）的文件，你应该使用 <code>1048576</code>（即1024*1024）作为参数，如下所示：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rand</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -out</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> random.bin</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1048576</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这个命令会生成一个包含1048576字节（即1024KB或1MB）随机数据的文件 <code>random.bin</code>。</p><hr><h2 id="openssl-检测哈希值" tabindex="-1">OpenSSL 检测哈希值 <a class="header-anchor" href="#openssl-检测哈希值" aria-label="Permalink to &quot;OpenSSL 检测哈希值&quot;">​</a></h2><p>在 OpenSSL 中，你可以使用 <code>dgst</code> 命令来计算文件的哈希值。以下是具体的步骤：</p><ol><li>首先，你需要打开终端。</li><li>然后，导航到包含你想要检测的文件的目录。</li><li>使用 <code>openssl dgst</code> 命令加上你想要使用的哈希算法和文件名。</li></ol><p>例如，如果你想要计算一个文件的 SHA-256 哈希值，你可以使用以下的命令：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dgst</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sha256</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> filename</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>请将 <code>filename</code> 替换为你想要检测的文件的名称。</p><p>这个命令会计算文件的 SHA-256 哈希值，并将结果打印到终端。</p><hr><h2 id="生成-rsa-密钥" tabindex="-1">生成 RSA 密钥 <a class="header-anchor" href="#生成-rsa-密钥" aria-label="Permalink to &quot;生成 RSA 密钥&quot;">​</a></h2><p>在 OpenSSL 中，你可以使用以下的命令来生成 RSA 密钥对：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> genpkey</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -algorithm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> RSA</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -out</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> private_key.pem</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rsa</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pubout</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -in</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> private_key.pem</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -out</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> public_key.pem</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这两个命令的意思是：</p><ul><li><p><code>openssl genpkey -algorithm RSA -out private_key.pem</code>：这个命令会生成一个 RSA 私钥，并将其保存到 <code>private_key.pem</code> 文件中。</p></li><li><p><code>openssl rsa -pubout -in private_key.pem -out public_key.pem</code>：这个命令会从 <code>private_key.pem</code> 文件中提取公钥，并将其保存到 <code>public_key.pem</code> 文件中。</p></li></ul><p>完成以上步骤后，你就会得到一个 RSA 密钥对，私钥保存在 <code>private_key.pem</code> 文件中，公钥保存在 <code>public_key.pem</code> 文件中。</p><hr><h2 id="openssl-支持的算法" tabindex="-1">OpenSSL 支持的算法 <a class="header-anchor" href="#openssl-支持的算法" aria-label="Permalink to &quot;OpenSSL 支持的算法&quot;">​</a></h2><p>OpenSSL 支持多种加密算法，包括对称加密算法、非对称加密算法和哈希函数。你可以使用以下的命令来列出 OpenSSL 支持的所有算法：</p><ol><li><p>列出所有的对称加密算法：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -cipher-algorithms</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p>列出所有的非对称加密算法：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -public-key-algorithms</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p>列出所有的哈希函数：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -digest-commands</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li></ol><p>这些命令会列出 OpenSSL 支持的所有对应类型的算法。请注意，可用的算法可能会根据你的 OpenSSL 版本和配置有所不同。</p>`,54)]))}const F=i(n,[["render",l]]);export{c as __pageData,F as default};
